@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <span class="small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task)" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task)" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="Priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="DueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@IsSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="text-danger small mt-1">@ErrorMessage</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = string.Empty;
    private string Assignee = string.Empty;
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private string? ErrorMessage;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title))
        {
            ErrorMessage = "Title is required.";
            return;
        }

        ErrorMessage = null;
        IsSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync(
                new TaskItem(0, Title.Trim(), Assignee.Trim(), Priority, DueDate, Status));
            ResetForm();
            IsVisible = false;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void ResetForm()
    {
        Title = string.Empty;
        Assignee = string.Empty;
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
        ErrorMessage = null;
    }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@* A single Kanban column displaying filtered tasks, move actions, and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          IsMoving="IsMoving"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }
        </div>
        <div class="card-footer p-2">
            <AddTaskForm Status="@Status" OnTaskCreated="OnTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Status="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     IsMoving="isMoving"
                     OnMoveRight="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Status="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     IsMoving="isMoving"
                     OnMoveLeft="task => MoveTask(task, "To Do")"
                     OnMoveRight="task => MoveTask(task, "Done")"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Status="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     IsMoving="isMoving"
                     OnMoveLeft="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private bool isMoving;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t =>
                t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        isMoving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isMoving = false;
        }
    }

    private async Task HandleTaskCreated(TaskItem formData)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

